const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

function openDb() {
    return new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const db = e.target.result;
            if (!db.objectStoreNames.contains('sites')) {
                db.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!db.objectStoreNames.contains('inspections')) {
                const store = db.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

function tx(storeName, mode) {
    return openDb().then(db => {
        const transaction = db.transaction(storeName, mode);
        const store = transaction.objectStore(storeName);
        return { db, store, transaction };
    });
}

function promisifyRequest(request) {
    return new Promise((resolve, reject) => {
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });
}

// Sites
export async function getAllSites() {
    const { store } = await tx('sites', 'readonly');
    return promisifyRequest(store.getAll());
}

export async function saveSite(site) {
    const { store } = await tx('sites', 'readwrite');
    return promisifyRequest(store.put(site));
}

export async function deleteSite(siteId) {
    const { store } = await tx('sites', 'readwrite');
    return promisifyRequest(store.delete(siteId));
}

// Inspections
export async function getAllInspections() {
    const { store } = await tx('inspections', 'readonly');
    return promisifyRequest(store.getAll());
}

export async function getInspection(id) {
    const { store } = await tx('inspections', 'readonly');
    return promisifyRequest(store.get(id));
}

export async function getInspectionsBySite(siteId) {
    const { store } = await tx('inspections', 'readonly');
    const index = store.index('siteId');
    return promisifyRequest(index.getAll(siteId));
}

export async function saveInspection(inspection) {
    const { store } = await tx('inspections', 'readwrite');
    return promisifyRequest(store.put(inspection));
}

export async function deleteInspection(id) {
    const { store } = await tx('inspections', 'readwrite');
    return promisifyRequest(store.delete(id));
}

export async function getUnsyncedInspections() {
    const { store } = await tx('inspections', 'readonly');
    const all = await promisifyRequest(store.getAll());
    return all.filter(i => !i.isSynced);
}

export async function markAsSynced(id) {
    const { store } = await tx('inspections', 'readwrite');
    const inspection = await promisifyRequest(store.get(id));
    if (inspection) {
        inspection.isSynced = true;
        return promisifyRequest(store.put(inspection));
    }
}

// Photo helper - reads file input and returns base64
export function readFileAsBase64(inputElement) {
    return new Promise((resolve, reject) => {
        const file = inputElement.files[0];
        if (!file) { resolve(null); return; }
        const reader = new FileReader();
        reader.onload = () => resolve({
            fileName: file.name,
