arguments.file_text:
:root {
    --primary: #e94560;
    --primary-dark: #c23152;
    --bg: #f8f9fa;
    --surface: #ffffff;
    --text: #1a1a2e;
    --text-muted: #6c757d;
    --border: #dee2e6;
    --success: #28a745;
    --warning: #ffc107;
    --danger: #dc3545;
    --radius: 12px;
    --shadow: 0 2px 8px rgba(0,0,0,0.08);
}

* {
    box-sizing: border-box;
    -webkit-tap-highlight-color: transparent;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 16px;
    -webkit-font-smoothing: antialiased;
    overscroll-behavior: none;
}

.app-container {
    display: flex;
    flex-direction: column;
    min-height: 100dvh;
    max-width: 600px;
    margin: 0 auto;
}

.app-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    background: var(--text);
    color: white;
    position: sticky;
    top: 0;
    z-index: 100;
}

.app-title {
    font-size: 1.2rem;
    font-weight: 700;
    color: white;
    text-decoration: none;
}

.sync-status {
    font-size: 0.85rem;
}

.badge-pending {
    background: var(--warning);
    color: var(--text);
    padding: 4px 8px;
    border-radius: 12px;
    font-weight: 600;
}

.badge-synced {
    color: var(--success);
    font-size: 1.2rem;
}

.app-nav {
    display: flex;
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    position: sticky;
    top: 52px;
    z-index: 99;
}

.nav-tab {
    flex: 1;
    text-align: center;
    padding: 12px;
    text-decoration: none;
    color: var(--text-muted);
    font-weight: 500;
    font-size: 0.9rem;
    border-bottom: 3px solid transparent;
    transition: all 0.15s;
}

.nav-tab:hover, .nav-tab.active {
    color: var(--primary);
    border-bottom-color: var(--primary);
}

.app-content {
    flex: 1;
    padding: 16px;
    padding-bottom: 80px;
}

/* Cards */
.card {
    background: var(--surface);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    padding: 16px;
    margin-bottom: 12px;
    border: 1px solid var(--border);
}

.card-title {
    font-size: 1rem;
    font-weight: 600;
    margin: 0 0 4px;
}

.card-subtitle {
    font-size: 0.85rem;
    color: var(--text-muted);
    margin: 0;
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 12px 20px;
    border: none;
    border-radius: var(--radius);
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    transition: transform 0.1s, background 0.15s;
    text-decoration: none;
    touch-action: manipulation;
}

.btn:active {
    transform: scale(0.96);
}

.btn-primary {
    background: var(--primary);
    color: white;
}

.btn-primary:hover {
    background: var(--primary-dark);
}

.btn-secondary {
    background: var(--border);
    color: var(--text);
}

.btn-success {
    background: var(--success);
    color: white;
}

.btn-danger {
    background: var(--danger);
    color: white;
}

.btn-block {
    display: flex;
    width: 100%;
}

.btn-fab {
    position: fixed;
    bottom: 24px;
    right: 24px;
    width: 60px;
    height: 60px;
    border-radius: 50%;
    font-size: 1.5rem;
    box-shadow: 0 4px 12px rgba(233, 69, 96, 0.4);
    z-index: 50;
}

/* Forms */
.form-group {
    margin-bottom: 16px;
}

.form-group label {
    display: block;
    font-size: 0.85rem;
    font-weight: 600;
    margin-bottom: 6px;
    color: var(--text-muted);
}

.form-control {
    width: 100%;
    padding: 12px;
    border: 1px solid var(--border);
    border-radius: 8px;
    font-size: 1rem;
    transition: border-color 0.15s;
}

.form-control:focus {
    outline: none;
    border-color: var(--primary);
    box-shadow: 0 0 0 3px rgba(233, 69, 96, 0.1);
}

textarea.form-control {
    min-height: 80px;
    resize: vertical;
}

/* Checklist */
.checklist-category {
    font-size: 0.8rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: var(--primary);
    margin: 20px 0 8px;
    padding: 0 4px;
}

.checklist-item {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 14px 12px;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 8px;
    margin-bottom: 8px;
    transition: background 0.1s;
}

.checklist-item.pass {
    border-left: 4px solid var(--success);
    background: #f0fff4;
}

.checklist-item.fail {
    border-left: 4px solid var(--danger);
    background: #fff5f5;
}

.checklist-item.na {
    border-left: 4px solid var(--text-muted);
    opacity: 0.7;
}

.checklist-text {
    flex: 1;
    font-size: 0.95rem;
}

.status-buttons {
    display: flex;
    gap: 4px;
}

.status-btn {
    width: 36px;
    height: 36px;
    border: 1px solid var(--border);
    border-radius: 8px;
    background: var(--bg);
    font-size: 1rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform 0.1s;
    touch-action: manipulation;
}

.status-btn:active {
    transform: scale(0.9);
}

.status-btn.active-pass {
    background: var(--success);
    color: white;
    border-color: var(--success);
}

.status-btn.active-fail {
    background: var(--danger);
    color: white;
    border-color: var(--danger);
}

.status-btn.active-na {
    background: var(--text-muted);
    color: white;
    border-color: var(--text-muted);
}

/* Photos */
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
    margin-top: 12px;
}

.photo-thumb {
    aspect-ratio: 1;
    border-radius: 8px;
    object-fit: cover;
    width: 100%;
    border: 1px solid var(--border);
}

.photo-add {
    aspect-ratio: 1;
    border-radius: 8px;
    border: 2px dashed var(--border);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2rem;
    color: var(--text-muted);
    cursor: pointer;
    transition: border-color 0.15s;
}

.photo-add:hover {
    border-color: var(--primary);
    color: var(--primary);
}

/* Empty state */
.empty-state {
    text-align: center;
    padding: 48px 24px;
    color: var(--text-muted);
}

.empty-state-icon {
    font-size: 3rem;
    margin-bottom: 12px;
}

/* Page header */
.page-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 20px;
}

.page-header h1 {
    font-size: 1.3rem;
    margin: 0;
    flex: 1;
}

.back-btn {
    font-size: 1.5rem;
    text-decoration: none;
    color: var(--text);
    padding: 4px;
}

/* Utilities */
.mt-2 { margin-top: 12px; }
.mb-2 { margin-bottom: 12px; }
.text-muted { color: var(--text-muted); }
.text-sm { font-size: 0.85rem; }
.flex-between { display: flex; justify-content: space-between; align-items: center; }

#blazor-error-ui {
    background: var(--danger);
    color: white;
    padding: 12px;
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 1000;
    display: none;
}

#blazor-error-ui[style] {
    display: block;
}

