@page "/"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <h1>Construction Sites</h1>
</div>

@if (_showAddForm)
{
    <div class="modal-overlay" @onclick="() => _showAddForm = false">
        <div class="modal-content" @onclick:stopPropagation="true">
            <h2>Add Site</h2>
            <div class="form-group">
                <label>Site Name</label>
                <input class="form-control" @bind="_newSite.Name" placeholder="e.g. Riverside Tower Block A" />
            </div>
            <div class="form-group">
                <label>Address</label>
                <input class="form-control" @bind="_newSite.Address" placeholder="123 Main Street" />
            </div>
            <button class="btn btn-primary btn-block" @onclick="SaveSite">Add Site</button>
        </div>
    </div>
}

@if (_sites.Count == 0)
{
    <div class="empty-state">
        <div class="empty-state-icon">🏗️</div>
        <p>No construction sites yet.<br/>Tap + to add your first site.</p>
    </div>
}
else
{
    @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
    {
        <div class="card" @onclick="() => Nav.NavigateTo($&quot;/site/{site.Id}&quot;)">
            <p class="card-title">@site.Name</p>
            <p class="card-subtitle">📍 @site.Address</p>
        </div>
    }
}

<button class="btn btn-primary btn-fab" @onclick="() => _showAddForm = true">+</button>

@code {
    private List<ConstructionSite> _sites = new();
    private ConstructionSite _newSite = new();
    private bool _showAddForm;

    protected override async Task OnInitializedAsync()
    {
        _sites = await Storage.GetSitesAsync();
    }

    private async Task SaveSite()
    {
        if (string.IsNullOrWhiteSpace(_newSite.Name)) return;
        await Storage.SaveSiteAsync(_newSite);
        _sites.Add(_newSite);
        _newSite = new();
        _showAddForm = false;
    }
}

@page "/site/{SiteId}"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <a href="/" class="back-btn">←</a>
    <h1>@_site?.Name</h1>
</div>

@if (_site is not null)
{
    <p class="text-muted text-sm">📍 @_site.Address</p>

    <button class="btn btn-primary btn-block mb-2" @onclick="StartNewInspection">
        📋 New Inspection
    </button>

    <h2 style="font-size:1.1rem; margin-top:24px;">Past Inspections</h2>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }
    else
    {
        @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
        {
            <div class="card" @onclick="() => Nav.NavigateTo($&quot;/inspection/{inspection.Id}&quot;)">
                <div class="flex-between">
                    <p class="card-title">@inspection.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</p>
                    @if (!inspection.IsSynced)
                    {
                        <span class="badge-pending" style="font-size:0.7rem">⏳</span>
                    }
                </div>
                <p class="card-subtitle">👷 @inspection.InspectorName</p>
                <div class="summary-row">
                    @{ var pass = inspection.ChecklistItems.Count(c => c.Status == CheckStatus.Pass); }
                    @{ var fail = inspection.ChecklistItems.Count(c => c.Status == CheckStatus.Fail); }
                    @{ var unchecked = inspection.ChecklistItems.Count(c => c.Status == CheckStatus.NotChecked); }
                    @if (pass > 0) { <span class="summary-badge pass">✓ @pass</span> }
                    @if (fail > 0) { <span class="summary-badge fail">✗ @fail</span> }
                    @if (unchecked > 0) { <span class="summary-badge pending">? @unchecked</span> }
                    @if (inspection.Photos.Count > 0) { <span class="summary-badge" style="background:#e3f2fd;color:#1565c0;">📷 @inspection.Photos.Count</span> }
                </div>
            </div>
        }
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        var sites = await Storage.GetSitesAsync();
        _site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspections = await Storage.GetInspectionsAsync(SiteId);
    }

    private void StartNewInspection()
    {
        Nav.NavigateTo($"/inspection/new/{SiteId}");
    }
}

@page "/inspection/new/{SiteId}"
@page "/inspection/{InspectionId}"
@inject ILocalStorageService Storage
@inject NavigationManager Nav
@inject SyncService Sync
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="page-header">
    <a href="@BackUrl" class="back-btn">←</a>
    <h1>@(_isNew ? "New Inspection" : "Inspection")</h1>
    @if (!_isNew)
    {
        <span class="text-sm text-muted">@_inspection.CreatedAt.ToLocalTime().ToString("MMM dd")</span>
    }
</div>

@if (_inspection is not null)
{
    <div class="form-group">
        <label>Inspector Name</label>
        <input class="form-control" @bind="_inspection.InspectorName" placeholder="Your name" />
    </div>

    <!-- Checklist -->
    @{ string? lastCategory = null; }
    @foreach (var item in _inspection.ChecklistItems)
    {
        @if (item.Category != lastCategory)
        {
            lastCategory = item.Category;
            <div class="checklist-category">@item.Category</div>
        }

        <div class="checklist-item @GetItemClass(item)">
            <span class="checklist-text">@item.Description</span>
            <div class="status-buttons">
                <button class="status-btn @(item.Status == CheckStatus.Pass ? "active-pass" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.Pass)" title="Pass">✓</button>
                <button class="status-btn @(item.Status == CheckStatus.Fail ? "active-fail" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.Fail)" title="Fail">✗</button>
                <button class="status-btn @(item.Status == CheckStatus.NotApplicable ? "active-na" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.NotApplicable)" title="N/A">—</button>
            </div>
        </div>

        @if (item.Status == CheckStatus.Fail)
        {
            <div style="margin: -4px 0 8px 16px;">
                <input class="form-control" style="font-size:0.85rem; padding:8px;"
                       @bind="item.Notes" placeholder="Note about this issue..." />
            </div>
        }
    }

    <!-- Notes -->
    <div class="form-group" style="margin-top: 24px;">
        <label>General Notes</label>
        <textarea class="form-control" @bind="_inspection.Notes" placeholder="Additional observations, concerns, follow-up items..."></textarea>
    </div>

    <!-- Photos -->
    <div class="form-group">
        <label>Photos (@_inspection.Photos.Count)</label>
        <div class="photo-grid">
            @foreach (var photo in _inspection.Photos)
            {
                <img class="photo-thumb" src="data:image/jpeg;base64,@photo.DataBase64" alt="@photo.Caption" />
            }
            <label class="photo-add">
                📷
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment"
                           style="display:none;" />
            </label>
        </div>
    </div>

    <!-- Save -->
    <button class="btn btn-success btn-block" @onclick="SaveInspection" style="margin-top:24px;">
        💾 Save Inspection
    </button>
}

@code {
    [Parameter] public string? SiteId { get; set; }
    [Parameter] public string? InspectionId { get; set; }

    private Inspection _inspection = new();
    private bool _isNew;
    private IJSObjectReference? _module;

    private string BackUrl => _isNew ? $"/site/{SiteId}" : $"/site/{_inspection.SiteId}";

    protected override async Task OnInitializedAsync()
    {
        if (!string.IsNullOrEmpty(InspectionId) && InspectionId != "new")
        {
            var existing = await Storage.GetInspectionAsync(InspectionId);
            if (existing is not null)
            {
                _inspection = existing;
                _isNew = false;
                return;
            }
        }

        // New inspection
        _isNew = true;
        var sites = await Storage.GetSitesAsync();
        var site = sites.FirstOrDefault(s => s.Id == SiteId);
        _inspection = new Inspection
        {
            SiteId = SiteId ?? "",
            SiteName = site?.Name ?? "",
            ChecklistItems = SafetyChecklist.GetDefaultChecklist()
        };
    }

    private void SetStatus(ChecklistItem item, CheckStatus status)
    {
        item.Status = item.Status == status ? CheckStatus.NotChecked : status;
    }

    private string GetItemClass(ChecklistItem item) => item.Status switch
    {
        CheckStatus.Pass => "pass",
        CheckStatus.Fail => "fail",
        CheckStatus.NotApplicable => "na",
        _ => ""
    };

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file is null) return;

        // Resize for mobile - max 1024px wide
        var resized = await file.RequestImageFileAsync("image/jpeg", 1024, 1024);
        using var stream = resized.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);

        var photo = new InspectionPhoto
        {
            FileName = file.Name,
            DataBase64 = Convert.ToBase64String(ms.ToArray()),
            TakenAt = DateTime.UtcNow
        };

        _inspection.Photos.Add(photo);
    }

    private async Task SaveInspection()
    {
        _inspection.IsSynced = false;
        await Storage.SaveInspectionAsync(_inspection);
        await Sync.UpdatePendingCountAsync();
        Nav.NavigateTo($"/site/{_inspection.SiteId}");
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
            await _module.DisposeAsync();
    }
