                        @onclick="() => SetStatus(item, CheckStatus.Pass)" title="Pass">✓</button>
                <button class="status-btn @(item.Status == CheckStatus.Fail ? "active-fail" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.Fail)" title="Fail">✗</button>
                <button class="status-btn @(item.Status == CheckStatus.NotApplicable ? "active-na" : "")"
                        @onclick="() => SetStatus(item, CheckStatus.NotApplicable)" title="N/A">—</button>
