toolArgs.file_text:
@page "/inspections"
@inject ILocalStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <h1>All Inspections</h1>
</div>

@if (_inspections.Count == 0)
{
    <div class="empty-state">
        <div class="empty-state-icon">📋</div>
        <p>No inspections recorded yet.<br/>Go to a site to start an inspection.</p>
    </div>
}
else
{
    @foreach (var inspection in _inspections.OrderByDescending(i => i.CreatedAt))
    {
        <div class="card" @onclick="() => Nav.NavigateTo($&quot;/inspection/{inspection.Id}&quot;)">
            <div class="flex-between">
                <p class="card-title">@inspection.SiteName</p>
                @if (!inspection.IsSynced)
                {
                    <span class="badge-pending" style="font-size:0.7rem">⏳ pending</span>
                }
                else
                {
                    <span class="text-sm" style="color:var(--success)">✓ synced</span>
                }
            </div>
            <p class="card-subtitle">
                @inspection.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt") · 👷 @inspection.InspectorName
            </p>
            <div class="summary-row">
                @{ var pass = inspection.ChecklistItems.Count(c => c.Status == CheckStatus.Pass); }
                @{ var fail = inspection.ChecklistItems.Count(c => c.Status == CheckStatus.Fail); }
                @if (pass > 0) { <span class="summary-badge pass">✓ @pass passed</span> }
                @if (fail > 0) { <span class="summary-badge fail">✗ @fail failed</span> }
                @if (inspection.Photos.Count > 0) { <span class="summary-badge" style="background:#e3f2fd;color:#1565c0;">📷 @inspection.Photos.Count photos</span> }
            </div>
        </div>
    }
}

@code {
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        _inspections = await Storage.GetInspectionsAsync();
    }
}

